var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"Huh…","TWN":"這是……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……재미있군요.","JPN":"……面白いですね。","ENG":"Well, this is interesting…","TWN":"……真有意思。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국의 기밀 함선인 방주는 클리파 차원과 현실의 통로를 막는 역할을 하고 있죠.","JPN":"管理局の機密艦船である箱舟は、クリファ次元と現実の通路を塞ぐ役割を果たしています。","ENG":"The Administration used its highly-classified Ark to block the path between Qlipha dimension and our world.","TWN":"管理局機密艦船 方舟的作用是堵住逆卡巴拉次元和現世間的通道。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트의 마왕과 그 사도들의 힘을 억제하기 위해서요.","JPN":"クリフォトの魔王とその使徒たちの力を抑制するためです。","ENG":"This was to deter the Demon Lords of Qliphoth and their Apostles.","TWN":" 目的是克制魔王和那些使徒的力量。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 통로에 간섭할 수 있다면, 반대로 활용할 수도 있다는 뜻입니다.","JPN":"しかし、通路に干渉できるということは、逆に利用することもできるということです。","ENG":"But if one can intervene in this path, that means it's also possible to exploit this.","TWN":"但若是可以干涉通道，那就表示也可以逆向操作。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"방주를 침식시켜 클리파 차원과의 통로를 확장하는 데 사용하다니…….","JPN":"箱舟を侵食させて、クリファ次元との通路を拡張するために使うなんて……","ENG":"Someone got the idea to corrupt the Ark itself to expand the path to Qlipha…","TWN":"竟然想到侵蝕方舟來擴充和逆卡巴拉次元間的通道……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"누구인지는 몰라도 꽤 참신한 발상을 떠올렸네요.","JPN":"誰かはわかりませんが、かなり斬新な発想ですね。","ENG":"I've got to say it was pretty innovative, whoever it was that thought of it.","TWN":"雖然不知道那個人是誰，但他真是天才。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……방주에 대해 꽤 잘 알고 있군.","JPN":"……箱舟についてかなり詳しいようだな。","ENG":"…You seem very familiar with the Ark.","TWN":"……你很清楚方舟的事嘛！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러고 보니 이수연, 너도 방주의 존재에 대해 알고 나를 여기로 보냈지.","JPN":"そういえばカナミ、お前も箱舟の存在について知った上で私をここに送ったな。","ENG":"Come to think of it, you sent me here in full knowledge of the Ark as well, Sooyeon.","TWN":"這麼說來，李秀妍你也是知道方舟的事，才會把我弄來這裡的吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그것도 이 녀석이 알려 준 거냐?","JPN":"それもこいつが教えてくれたのか？","ENG":"Did you hear about that from this fool?","TWN":"也是這傢伙告訴你的嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……글쎄요, 어떨까요?","JPN":"……さあ、どうですかね。","ENG":"Well... What do you think?","TWN":"……這個嘛？你說呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"코핀 시리즈가 방주라는 건 구 관리국 시절에도 기밀 중의 기밀이었다.","JPN":"コフィンシリーズが箱舟というのは、旧管理局時代の機密中の機密だった。","ENG":"The fact that the Coffin series are Arks was one of the closest held secrets even during the Old Administration.","TWN":"科芬系列是方舟的事，在舊管理局時期也是機密中的機密。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나유빈, 넌 대체 어디까지 알고 있는 거지?","JPN":"イチノセ・カオル、お前はいったいどこまで知っているんだ？","ENG":"How much do you know exactly, Na Yubin?","TWN":"羅瑜斌，你到底知道多少？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……아주 먼 옛날, 최초의 세계에서 만들어진 관리국의 첫 번째 차원함선들이라는 것 정도는 알고 있습니다.","JPN":"……はるか昔、最初の世界で作られた管理局の最初の次元艦船ということぐらいは知っています。","ENG":"Only that they were the first dimensional ships built by the Administration long, long ago… in the very first world.","TWN":"……就很久以前，管理局在起初世界中首次打造的那些次元艦船。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 단순히 <color=#ffd34c>심도</color>로 나눠진 이면세계들이 아니라, 완전한 세계선 이동이 가능하다는 것도 말이죠.","JPN":"そして単純に<color=#ffd34c>深度</color>で分かれた裏世界ではなく、完全な世界線移動が可能だということもですね。","ENG":"And also that they can jump between entire worldlines, instead of merely diving to different <color=#ffd34c>depths</color> in the Counterside.","TWN":"而且那些不是單純以<color=#ffd34c>深度</color>區分的異界，而是可以完整的世界線移動。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그걸, 네가 어떻게……?","JPN":"そんなこと、お前がどうして……？","ENG":"How… How would you know that?","TWN":"你怎麼會知道……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"펜릴 전대에 있을 때 어떤 사람과 만난 적이 있습니다.","JPN":"フェンリル戦隊にいた時、ある人と出会ったんです。","ENG":"I met someone when I was with Fenrir.","TWN":"我在芬里爾戰隊時曾到遇到一個人。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그때서야 알게 됐죠. 그가 바로 구 관리국을 만든 <color=#ffd34c>관리자</color>라는 사실을요.","JPN":"その時ようやく気づいたのです。まさしく彼が旧管理局を創った<color=#ffd34c>管理者</color>という事実を。","ENG":"That's when I found out… This person was the <color=#ffd34c>Administrator</color> who founded the Old Administration.","TWN":"我那時候才知道，原來他就是創造管理局的<color=#ffd34c>管理者</color>。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그 녀석을 만났다고?!","JPN":"あいつに会っただと！？","ENG":"You met him?!","TWN":"你見過他？！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"역시, 스승님도 아는 분이셨군요.","JPN":"やはり、師匠も知っている方だったんですね。","ENG":"Just as I suspected… You know him too, huh.","TWN":"師父果然也認識他。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그분은 저한테 <color=#ffd34c>2급 관리자</color> 역할을 맡지 않겠냐고 제안했습니다.","JPN":"あの方は僕に<color=#ffd34c>2級管理者</color>の役を務めないかと提案してきました。","ENG":"He offered to make me a <color=#ffd34c>Class 2 Administrator</color>.","TWN":"他問我願不願意擔任<color=#ffd34c>2級管理者</color>，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저는 펜릴 전대에 남고 싶어서, 정중히 거절했지만요.","JPN":"僕はフェンリル戦隊に残りたかったので、丁重に断りましたが。","ENG":"I politely refused of course, since I wanted to stay with Fenrir at the time.","TWN":"我當時很慎重地回絕他，並且表示我想待在芬里爾戰隊裡。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 그 뒤에 확인해 보니 어째서인지 제 보안 등급이 관리자 급으로 상향 조정됐더군요.","JPN":"しかし、その後確認してみたら、なぜか僕のセキュリティ等級が管理者級に上方修正されていました。","ENG":"It was only later when I found out that my security clearance was elevated to an administrator level for some reason.","TWN":"但後來不知道為什麼，我的安全層級被調高至管理者層級。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"덕분에 기밀 정보는 물론, 관리실패 때 파괴되지 않은 구 관리국의 유물 중 일부도 제 손에 들어왔죠.","JPN":"おかげで機密情報はもちろん、管理失敗の時に破壊されなかった旧管理局の遺物の一部も手に入りました。","ENG":"So with that, I gained access to not only the most highly classified information, but also some of the Old Administration's artifacts that survived the Administration Failure.","TWN":"因為這樣，無論是機密資料，或是管理失敗當時未破壞的舊管理局遺物中，有部分也落入我的手裡。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 그래서 지금도 활동하는 데 신세를 많이 지고 있어요.","JPN":"まあ、おかげで最近の活動にもかなり役立っています。","ENG":"They've been pretty helpful with my recent activity, I must say.","TWN":"現在也因為這樣而受惠不少呢。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"비밀조직 운영이라는 게 실제로 해 보니까 생각보다 힘들더라고요.","JPN":"秘密組織の運営を実際にやってみると、想像よりも大変でして。","ENG":"Running a secret organization turned out to be a lot tougher than I thought.","TWN":"沒想到經營神秘組織其實滿辛苦的呢。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어쩌면 그분은 일이 이렇게 될 줄 알고 제안하셨을지도 모르죠.","JPN":"もしかしたら、あの方はこうなることを想定して提案してくださったのかもしれません。","ENG":"Maybe he made me that offer because he saw all this coming.","TWN":"他可能早就料到事情會變成這樣才會那樣問我吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리실패 이후로 만나뵌 적이 없어서 어떨지는 모르겠지만……","JPN":"管理失敗以来、お会いしたことがないのでハッキリとはわかりませんが……","ENG":"I have no idea how he's been doing, as I haven't met with him since the Failure…","TWN":"管理失敗後我就沒再見過他，不知道他現在還好嗎……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"분명 살아 계시겠죠. 나중에 다시 뵙게 되면 감사 인사라도 드려야겠어요.","JPN":"きっと生きていらっしゃるでしょう。\\nまたお目にかかるチャンスがあれば、御礼を申し上げなければなりませんね。","ENG":"But I'm sure he's still alive. I'd better thank him if I ever get to see him again.","TWN":"但我相信他應該活著！之後如果有機會再見到他，我一定要好好謝謝他。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그랬군. 그 녀석이 네게……","JPN":"そうか。あいつがお前に……","ENG":"I see. So he came to you…","TWN":"原來如此，他向你……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"하지만…… 왜 하필?","JPN":"しかし……なぜよりによって？","ENG":"But why you, of all people?","TWN":"可是……為什麼偏偏？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"옛날 이야기는 작전 끝나고 두 분이서 따로 커피숍에나 가서 하시죠.","JPN":"思い出話は作戦が終わった後、お二人で喫茶店にでも行って続けてください。","ENG":"You can keep reminiscing at a nice coffee shop somewhere AFTER the mission.","TWN":"敘舊的話等作戰完畢二位再去咖啡廳慢慢聊吧！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"침식파 반응 다수가 그쪽으로 접근 중입니다.","JPN":"複数の侵食波反応がそちらに接近中です。","ENG":"I detect multiple Corruption Ray signatures headed your way.","TWN":"有大量的侵蝕波反應正在接近中。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사도의 직접 통제를 받는 침식체들입니다. 동급의 침식체들보다 위험도가 두 단계는 높다고 봐야 해요.","JPN":"使徒から直接統制を受けた侵食体です。同級の侵食体に比べ危険度が2段階は高いとみられます。","ENG":"These C.O.s are under the direct control of the Apostles. Their threat levels are at least two steps higher than other C.O.s of the same class.","TWN":"那些侵蝕體是使徒親自操控的，會比同類的侵蝕體還難對付。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 걱정해 주는 건 고맙지만 스승님은 무적의 전 펜릴 전대장님이시라고, 수연아.","JPN":"ハハ、心配してくれるのはありがたいけど、師匠は無敵の元フェンリル戦隊長さ、キズナ。","ENG":"Haha, I appreciate the concern, but Master is the invincible former Commander of the Fenrir Division, Sooyeon.","TWN":"呵呵～多謝你的操心，但師父可是無敵芬里爾戰隊的隊長，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런 말을 하면 스승님이 자존심 상할지도 몰라.","JPN":"そんなこと言ったら師匠のプライドを傷つけるかもしれないよ。","ENG":"You might hurt her pride if you say things like that.","TWN":"我怕你說那些話會傷到她的自尊心。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"평소라면 그렇겠지. 하지만 거긴 이미 <color=#ffd34c>성역화</color>가 상당히 진행된 곳이야.","JPN":"いつもならそうでしょうね。でも、そこはすでに<color=#ffd34c>聖域化</color>がかなり進んでいるところよ。","ENG":"Usually, yes. But <color=#ffd34c>sanctification</color> is already well underway over there.","TWN":"要是平時我當然不會說這些，但那裡可是已經<color=#ffd34c>聖域化</color>到一定程度的地方。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"더구나 방주가 있는 좌표는 클리파 차원과 바로 이어지는 곳.","JPN":"しかも箱舟がある座標はクリファ次元とすぐ繋がる場所。","ENG":"Not to mention that the Ark's coordinates are right at the doorstep of Qlipha.","TWN":"再加上方舟所在的座標是連接逆卡巴拉次元的地方。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리에겐 최악, 놈들에겐 최적의 전장이지.","JPN":"私たちにとっては最悪、奴らにとっては最適の戦場ね。","ENG":"We couldn't ask for a worse playing field… and they for a better one.","TWN":"對我們來說超級不利，對敵人來說卻是超級有利！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래? 그렇게까지 말하니까 조금 긴장되는걸?","JPN":"そう？　そこまで言われたら少し緊張するな。","ENG":"Is that right? Okay, now I'm getting a bit nervous.","TWN":"是喔？被你說得連我都開始有點緊張呢！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이럴 때 스승님이 있어서 다행입니다.","JPN":"こんな時に師匠がいてくれて嬉しいです。","ENG":"Thank goodness I've got you here, Master.","TWN":"幸好這種時候有師父在。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이번엔 절 버리지 않으셨으면 좋겠네요.","JPN":"今度は僕を見捨てないでくださいね。","ENG":"I hope you won't abandon me this time.","TWN":"希望師父這次不要再拋下我們囉。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 농담입니다. 뭘 그렇게 정색하세요.","JPN":"ハハハ、冗談ですよ。そんなこわい顔で見ないでください。","ENG":"Hah hah. I was just kidding. Why so serious?","TWN":"呵，我開玩笑的，表情不要那麼嚴肅啦！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"사실 그때도…… 저희가 살아남은 건 스승님 덕분이라는 걸 전 알고 있어요.","JPN":"実はあの時も……僕たちが生き残ったのは師匠のおかげということを知っていましたよ。","ENG":"To be honest… I know we only survived before thanks to you.","TWN":"那個時候……也是因為師父我們才能夠活命。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래봐야 상황을 되돌리긴 너무 늦었지만요.","JPN":"だとしても、戻すには遅すぎますが。","ENG":"Although of course, it's too late to turn things around.","TWN":"雖然現在說這些也不能改變什麼。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너……?","JPN":"お前……？","ENG":"Wait… Do you…?","TWN":"你……？！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이런, 대화는 나중에 해야겠네요.","JPN":"おっと、話は後にしましょうか。","ENG":"Whoops, looks like we'll have to save the chitchat for later.","TWN":"可惡！打完再說吧！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"상대가 저흴 마중하러 온 것 같거든요.","JPN":"僕たちのお出迎えに来てくれたようです。","ENG":"Because it looks like they're throwing us a welcome party.","TWN":"他們還來迎接我們欸。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_CORRUPT","text":{"KOREA":"……죽여라! 제국의 적에게 죽음을!!","JPN":"……殺せ！　帝国の敵に死を！！","ENG":"…Die! Death to the Empire's enemies!!","TWN":"……給我殺！殺光那些帝國的敵人！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_CORRUPT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_CORRUPT","text":{"KOREA":"제국에 영광을! 성녀님의 이름으로!","JPN":"帝国に栄光を！　聖女様の名の下に！","ENG":"Glory to the Empire! In the name of the Saintess!","TWN":"為帝國的榮耀！以聖女之名！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_CORRUPT","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_43"}]`);export{e as default};